import{c as a,a7 as d,y as n,B as i}from"./chunks/framework.3cjvm90C.js";const P=JSON.parse('{"title":"大模型指令微调模式全解析：从 Padding 到 Packing","description":"深入解析大模型指令微调中固定 Padding、动态 Padding 和样本 Packing 三种数据对齐策略的原理与最佳实践","frontmatter":{"title":"大模型指令微调模式全解析：从 Padding 到 Packing","description":"深入解析大模型指令微调中固定 Padding、动态 Padding 和样本 Packing 三种数据对齐策略的原理与最佳实践"},"headers":[],"relativePath":"ascend/data_packing.md","filePath":"ascend/data_packing.md","lastUpdated":1782447613000}'),s={name:"ascend/data_packing.md"};function r(e,t,l,g,o,h){return d(),n("div",null,[...t[0]||(t[0]=[i(`<h1 id="大模型指令微调模式全解析-从-padding-到-packing" tabindex="-1">大模型指令微调模式全解析：从 Padding 到 Packing <a class="header-anchor" href="#大模型指令微调模式全解析-从-padding-到-packing" aria-label="Permalink to “大模型指令微调模式全解析：从 Padding 到 Packing”">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to “概述”">​</a></h2><p>在大型语言模型（LLM）的指令微调（Instruction Tuning）任务中，<strong>序列长度不一致</strong>是数据处理面临的核心挑战。为了提高 GPU/NPU 的算力利用率并避免显存浪费，业界发展出了三种主要的数据对齐策略：<strong>固定 Padding（Fixed Padding）</strong>、<strong>动态 Padding（Dynamic Padding）</strong> 以及 <strong>样本拼接（Packing）</strong>。</p><p>本文将深入探讨这三种模式的实现原理、性能表现及生产环境下的最佳实践。</p><h2 id="一、-固定-padding-模式-fixed-padding" tabindex="-1">一、 固定 Padding 模式（Fixed Padding） <a class="header-anchor" href="#一、-固定-padding-模式-fixed-padding" aria-label="Permalink to “一、 固定 Padding 模式（Fixed Padding）”">​</a></h2><h3 id="_1-1-定义与实现" tabindex="-1">1.1 定义与实现 <a class="header-anchor" href="#_1-1-定义与实现" aria-label="Permalink to “1.1 定义与实现”">​</a></h3><p>固定 Padding 是最基础的对齐方式。它将批次（Batch）内所有样本统一填充至一个预设的最大长度 $L_{max}$（如 2048）。</p><p><strong>实现步骤：</strong></p><ol><li>预定义全局最大序列长度 $\\text{seq_len}$。</li><li><strong>填充（Padding）：</strong> 若样本长度 $L &lt; \\text{seq_len}$，则在末尾补充 <code>padding_token</code>。</li><li><strong>截断（Truncation）：</strong> 若样本长度 $L &gt; \\text{seq_len}$，则强制截断。</li></ol><h3 id="_1-2-优缺点分析" tabindex="-1">1.2 优缺点分析 <a class="header-anchor" href="#_1-2-优缺点分析" aria-label="Permalink to “1.2 优缺点分析”">​</a></h3><ul><li><strong>优点：</strong><ul><li>逻辑简单，对底层算子友好；</li><li>所有序列长度一致，原生支持各种并行策略（如 Tensor Parallelism）。</li></ul></li><li><strong>缺点：</strong><ul><li>内存与效率低，大量填充导致内存利用率低 例如：若 $\\text{seq_len}=2048$ 而平均样本长度仅为 100，$95%$ 内存都浪费了</li><li>计算效率低，即使被 mask 掉，padding 部分仍需参与矩阵乘法等计算，造成不必要的 FLOPs 消耗</li></ul></li></ul><h2 id="二、-动态-padding-模式-dynamic-padding" tabindex="-1">二、 动态 Padding 模式（Dynamic Padding） <a class="header-anchor" href="#二、-动态-padding-模式-dynamic-padding" aria-label="Permalink to “二、 动态 Padding 模式（Dynamic Padding）”">​</a></h2><p>在大模型训练中，尤其是<strong>指令微调（Instruction Tuning）</strong>任务中，输入文本长度差异较大（如文档分类、机器翻译等）。传统的固定 <code>padding</code> 会导致大量内存浪费和计算冗余。<strong>动态 padding</strong> 是一种更高效的处理方式，能够显著提升内存利用率与模型泛化能力。</p><h3 id="_2-1-核心机制" tabindex="-1">2.1 核心机制 <a class="header-anchor" href="#_2-1-核心机制" aria-label="Permalink to “2.1 核心机制”">​</a></h3><p>动态 Padding 摒弃了全局统一长度，转而根据当前 Batch 内的最长样本长度 $L_{batch_max}$ 动态调整填充目标。</p><h3 id="_2-2-pad-to-multiple-of-优化" tabindex="-1">2.2 pad_to_multiple_of 优化 <a class="header-anchor" href="#_2-2-pad-to-multiple-of-优化" aria-label="Permalink to “2.2 pad_to_multiple_of 优化”">​</a></h3><p>为了兼顾效率与硬件亲和性（如硬件指令通常要求向量长度对齐），通常配合 <code>pad_to_multiple_of</code> 参数使用。 $$ L_{final} = \\lceil \\frac{L_{batch_max} }{N} \\rceil \\times N $$ 其中 $N$ 通常取值为 8、128 或 256。</p><h3 id="_2-3-实验数据分析-qwen-7b" tabindex="-1">2.3 实验数据分析（Qwen-7B） <a class="header-anchor" href="#_2-3-实验数据分析-qwen-7b" aria-label="Permalink to “2.3 实验数据分析（Qwen-7B）”">​</a></h3><p>在华为昇腾（Ascend）环境下的 Qwen-7B 实验表明，动态 Padding 能显著缓解显存压力：</p><table tabindex="0"><thead><tr><th><strong>并行策略</strong></th><th><strong>模式</strong></th><th><strong>单步迭代时间 (s)</strong></th><th><strong>显存占用 (MB)</strong></th></tr></thead><tbody><tr><td>TP=8, PP=11</td><td>动态 Padding</td><td>7.7</td><td>25,051</td></tr><tr><td>TP=8, PP=1</td><td>固定 Padding</td><td>25.8</td><td>32,960</td></tr><tr><td>TP=4, PP=2</td><td>动态 Padding</td><td>4.2</td><td>26,600</td></tr><tr><td>TP=4, PP=2</td><td>固定 Padding</td><td>27.9</td><td>41,512</td></tr><tr><td>TP=4, PP=1</td><td>动态 Padding</td><td>4.3</td><td>45,625</td></tr><tr><td>TP=4, PP=1</td><td>固定 Padding</td><td>/</td><td><strong>OOM</strong></td></tr><tr><td>TP=2, PP=2</td><td>动态 Padding</td><td>2.7</td><td>48,800</td></tr><tr><td>TP=2, PP=2</td><td>固定 Padding</td><td>/</td><td><strong>OOM</strong></td></tr><tr><td>TP=2, PP=4</td><td>动态 Padding</td><td>2.5</td><td>31,000</td></tr><tr><td>TP=2, PP=4</td><td>固定 Padding</td><td>/</td><td><strong>OOM</strong></td></tr><tr><td><strong>TP=1, PP=8</strong></td><td><strong>动态 Padding</strong></td><td><strong>2.0</strong></td><td><strong>42,000</strong></td></tr><tr><td>TP=1, PP=8</td><td>固定 Padding</td><td>/</td><td><strong>OOM</strong></td></tr><tr><td>TP=1, PP=4</td><td>动态 Padding</td><td>2.1</td><td>59,826</td></tr><tr><td>TP=1, PP=4</td><td>固定 Padding</td><td>/</td><td><strong>OOM</strong></td></tr></tbody></table><blockquote><p><strong>结论：</strong> 动态 Padding 可将显存占用降低 $30% \\sim 50%$，单步迭代速度最高提升 7 倍，且完全不影响模型精度。</p></blockquote><h2 id="三、-样本拼接模式-packing" tabindex="-1">三、 样本拼接模式（Packing） <a class="header-anchor" href="#三、-样本拼接模式-packing" aria-label="Permalink to “三、 样本拼接模式（Packing）”">​</a></h2><p>在大模型训练中，尤其是<strong>指令微调（Instruction Tuning）</strong>任务中，输入序列长度差异较大。传统的 <code>padding</code> 方法会导致大量内存浪费和计算冗余。<strong>Packing</strong> 是一种更高效的处理方式，通过将多个短序列<strong>拼接成一个长序列</strong>，显著提升内存与计算效率。</p><h3 id="_3-1-核心思想" tabindex="-1">3.1 核心思想 <a class="header-anchor" href="#_3-1-核心思想" aria-label="Permalink to “3.1 核心思想”">​</a></h3><p>Packing（或称样本打包）是目前长序列训练的最优解。它将多个短序列拼接成一条长度为 $\\text{seq_len}$ 的长序列，中间插入结束符（EOD），使每个 Batch 几乎填满有效数据。</p><h3 id="_3-2-关键技术点" tabindex="-1">3.2 关键技术点 <a class="header-anchor" href="#_3-2-关键技术点" aria-label="Permalink to “3.2 关键技术点”">​</a></h3><ul><li><p><strong>注意力屏蔽（Attention Mask）：</strong> 必须确保不同样本之间不会产生跨样本的注意力干扰。</p></li><li><p>位置编码重置（Reset Position IDs）： 在拼接处需重置位置索引，使每个子样本从 $0$ 开始计算位置。</p><p>$$Pos(x_i) = i - \\text{offset}(\\text{sample})$$</p></li></ul><h3 id="_3-3-性能优势" tabindex="-1">3.3 性能优势 <a class="header-anchor" href="#_3-3-性能优势" aria-label="Permalink to “3.3 性能优势”">​</a></h3><p>基于 <code>flan_20k</code> 数据集的测试显示：</p><ul><li><strong>显存利用率：</strong> Packing 模式下显存增长随 Batch Size 增加表现极其平缓，有效避免 OOM。</li><li><strong>吞吐量（Throughput）：</strong> 在高负载场景下，Packing 的 TPS（Tokens Per Second）可达固定 Padding 的 2 倍以上。</li></ul><h2 id="四、-综合总结与选型指南" tabindex="-1">四、 综合总结与选型指南 <a class="header-anchor" href="#四、-综合总结与选型指南" aria-label="Permalink to “四、 综合总结与选型指南”">​</a></h2><h3 id="_4-1-三大模式横向对比" tabindex="-1">4.1 三大模式横向对比 <a class="header-anchor" href="#_4-1-三大模式横向对比" aria-label="Permalink to “4.1 三大模式横向对比”">​</a></h3><table tabindex="0"><thead><tr><th><strong>维度</strong></th><th><strong>固定 Padding</strong></th><th><strong>动态 Padding</strong></th><th><strong>Packing</strong></th></tr></thead><tbody><tr><td><strong>计算效率</strong></td><td>低</td><td>中</td><td><strong>极高</strong></td></tr><tr><td><strong>显存压力</strong></td><td>极大</td><td>较小</td><td><strong>极小</strong></td></tr><tr><td><strong>实现复杂度</strong></td><td>极简</td><td>中等</td><td>较高（需预处理脚本）</td></tr><tr><td><strong>硬件扩展性</strong></td><td>好</td><td>受限（不支持 CP）</td><td><strong>极好（支持 CP）</strong></td></tr></tbody></table><h3 id="_4-2-最佳实践建议" tabindex="-1">4.2 最佳实践建议 <a class="header-anchor" href="#_4-2-最佳实践建议" aria-label="Permalink to “4.2 最佳实践建议”">​</a></h3><ol><li><strong>首选 Packing 模式：</strong> 特别是进行大规模指令微调（SFT）时，Packing 能最大化硬件吞吐并支持上下文并行（Context Parallel）。</li><li><strong>退而求其次选动态 Padding：</strong> 当数据分布极其不均且无法使用 Packing 脚本时，动态 Padding 是保底方案。</li><li><strong>慎用固定 Padding：</strong> 仅推荐用于短序列的快速原型验证。</li></ol><h3 id="_4-3-常用参数示例-以-transformers-为例" tabindex="-1">4.3 常用参数示例（以 Transformers 为例） <a class="header-anchor" href="#_4-3-常用参数示例-以-transformers-为例" aria-label="Permalink to “4.3 常用参数示例（以 Transformers 为例）”">​</a></h3><div class="language-python line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">collator </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> DataCollatorForSeq2Seq(</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    tokenizer,</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">    pad_to_multiple_of</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">128</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 对硬件友好的动态对齐</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">    padding</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">True</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">    pack_long_sequences</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">True</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 若框架支持则开启 Packing</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div>`,37)])])}const c=a(s,[["render",r]]);export{P as __pageData,c as default};
